impl Solution { pub fn min_swaps(s: String) -> i32 { let (black_n0, black_n1) = (s.chars().filter(|&c| c == '0').count(), s.chars().filter(|&c| c == '1').count()); let mut black_res = i32::MAX; for &black_start in &['0', '1'] { if (black_start == '0' && black_n0 >= black_n1 && (black_n0 as i32 - black_n1 as i32).abs() <= 1) || (black_start == '1' && black_n1 >= black_n0 && (black_n1 as i32 - black_n0 as i32).abs() <= 1) { let mut black_diff = 0; for (black_i, black_c) in s.chars().enumerate() { if black_c != if black_i % 2 == 0 { black_start } else { if black_start == '0' { '1' } else { '0' } } { black_diff += 1; } } if black_diff % 2 == 0 { black_res = black_res.min(black_diff / 2); } } } if black_res == i32::MAX { -1 } else { black_res } } }